use crate::pleromatic_frame::SwarmSignal;
use parking_lot::Mutex;
use std::collections::HashMap;
use std::net::UdpSocket;
use std::sync::Arc;
use std::time::Instant;

/// RemoteNode: Tracks the state of a peer Pleromatic hub.
#[derive(Clone, Debug)]
pub struct RemoteNode {
    pub last_seen: Instant,
    pub signal: SwarmSignal,
}

/// SwarmNet: Handles UDP broadcast and reception of swarm vibes.
/// This enables multi-node resonance without centralized coordination.
pub struct SwarmNet {
    socket: UdpSocket,
    pub registry: Arc<Mutex<HashMap<String, RemoteNode>>>,
}

impl SwarmNet {
    /// Create a new SwarmNet instance.
    /// Binds to the specified port and enables UDP broadcast.
    pub fn new(port: u16) -> std::io::Result<Self> {
        // Bind to all interfaces to listen for broadcasts
        let socket = UdpSocket::bind(format!("0.0.0.0:{}", port))?;
        socket.set_broadcast(true)?;
        socket.set_nonblocking(true)?;

        Ok(Self {
            socket,
            registry: Arc::new(Mutex::new(HashMap::new())),
        })
    }

    /// Broadcast the local swarm signal to all peers.
    pub fn broadcast(&self, signal: &SwarmSignal) -> std::io::Result<()> {
        let data = bincode::serialize(signal)
            .map_err(std::io::Error::other)?;

        // Broadcast to the local network on port 4242
        // In a real production mesh, this might be a multicast address or a list of peer IPs.
        self.socket.send_to(&data, "255.255.255.255:4242")?;
        Ok(())
    }

    /// Update the registry by receiving pending UDP datagrams.
    /// Should be called frequently in the main loop.
    pub fn update(&self) {
        let mut buf = [0u8; 1024];

        // Drain the UDP buffer
        while let Ok((amt, _src)) = self.socket.recv_from(&mut buf) {
            if let Ok(signal) = bincode::deserialize::<SwarmSignal>(&buf[..amt]) {
                // Ignore our own broadcasts (source_id would match)
                // But we let the caller handle that if they want to monitor their own loopback.

                let mut registry = self.registry.lock();
                registry.insert(
                    signal.source_id.clone(),
                    RemoteNode {
                        last_seen: Instant::now(),
                        signal,
                    },
                );
            }
        }

        // Prune stale nodes (15s timeout)
        let mut registry = self.registry.lock();
        registry.retain(|_, node| node.last_seen.elapsed().as_secs() < 15);
    }

    /// Calculate the collective vibe from all known active nodes.
    pub fn get_collective_vibe(&self, local_signal: &SwarmSignal) -> SwarmSignal {
        let registry = self.registry.lock();
        if registry.is_empty() {
            return local_signal.clone();
        }

        let mut total_energy = local_signal.energy;
        let mut total_consciousness = local_signal.consciousness;
        let mut count = 1;

        for node in registry.values() {
            total_energy += node.signal.energy;
            total_consciousness += node.signal.consciousness;
            count += 1;
        }

        SwarmSignal {
            source_id: "collective".to_string(),
            energy: total_energy / count,
            consciousness: total_consciousness / count,
            pitch_class: local_signal.pitch_class, // Local pitch usually leads or follows
            phase: local_signal.phase,
            recalibration_event: false,
        }
    }
}
